import pymysql
from aws_lambda_powertools import Tracer, Logger
tracer = Tracer()
logger = Logger()

@tracer.capture_kwargs
def search_products(event):
    db_host = "your-rds-host"
    db_name = "your-rds-db-name"
    db_user = "your-rds-username"
    db_password = "your-rds-password"

    conn = pymysql.connect(
        host=db_host,
        user=db_user,
        password=db_password,
        database=db_name
    )

    cur = conn.cursor(pymysql.cursors.DictCursor)

    search_params = event["queryStringParameters"]

    where_clause = ""
    params = []
    
    if "name" in search_params:
        where_clause += " AND product_name LIKE %s"
        params.append("%" + search_params["name"] + "%")

    if "description" in search_params:
        where_clause += " AND product_description LIKE %s"
        params.append("%" + search_params["description"] + "%")

    if where_clause != "":
        where_clause = "WHERE " + where_clause[5:]

    query = f"""
        SELECT *
        FROM products
        {where_clause}
    """

    cur.execute(query, tuple(params))

    results = cur.fetchall()

    conn.close()
    
    return {
        'statusCode': 200,
        'body': str(results)
    }

def lambda_handler(event, context):
    return search_products(event)